const response = $input.first().json;
const content = response.choices[0].message.content;

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Failed to parse OpenAI response: ${err.message}\nContent: ${content}`);
}

// Get job context from earlier node
const readResumeNode = $('Read Base Resume').first().json;
const company = readResumeNode.company_name || 'company';
const role = readResumeNode.role_title || 'role';
const jobId = readResumeNode.job_id;
const applyLink = readResumeNode.apply_link;
const matchScore = readResumeNode.skill_match_score;

// Sanitize version name
const rawName = `resume_${company}_${role}`.toLowerCase();
const versionName = rawName.replace(/[^a-z0-9_]/gi, '_').replace(/_+/g, '_').replace(/^_|_$/g, '');

// Build full resume text
const skillsList = (parsed.tailored_skills || []).join(', ');

let experienceText = '';
if (parsed.tailored_experience && Array.isArray(parsed.tailored_experience)) {
  experienceText = parsed.tailored_experience.map(exp => {
    const bullets = (exp.bullets || []).join('\n');
    return `## ${exp.role} @ ${exp.company} (${exp.duration})\n${bullets}`;
  }).join('\n\n');
}

const fullResumeText = [
  `# Kartik Anand`,
  ``,
  `## Professional Summary`,
  parsed.tailored_summary || '',
  ``,
  `## Skills`,
  skillsList,
  ``,
  `## Experience`,
  experienceText,
  ``,
  `## Education`,
  `IIT Bombay — Executive PG Diploma, ML & Data Science (2025–present)`,
  ``,
  `---`,
  `Tailored for: ${role} at ${company}`,
  `ATS Score Estimate: ${parsed.ats_score_estimate || 'N/A'}%`
].join('\n');

return [{
  json: {
    version_name: versionName,
    tailored_summary: parsed.tailored_summary || '',
    tailored_skills: parsed.tailored_skills || [],
    tailored_experience: parsed.tailored_experience || [],
    changes_made: parsed.changes_made || [],
    ats_score_estimate: parsed.ats_score_estimate || 0,
    full_resume_text: fullResumeText,
    job_id: jobId,
    company_name: company,
    role_title: role,
    apply_link: applyLink,
    match_score: matchScore
  }
}];

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const outputDir = '/home/ubuntu/resumes/tailored';

// Ensure directory exists
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const filePath = path.join(outputDir, `${data.version_name}.txt`);

try {
  fs.writeFileSync(filePath, data.full_resume_text, 'utf8');
} catch (err) {
  throw new Error(`Failed to write resume file: ${err.message}`);
}

return [{
  json: {
    ...data,
    file_path: filePath,
    saved: true
  }
}];

